// Patrón 3d-monitor channels.mjs (lectura; no se importa código).
const EVENT_CHANNEL = {
  PING: 'sys', PONG: 'sys',
  HORSE: 'agent', RABBIT: 'agent', SPIDER: 'agent',
  'selection:cast': 'game',
  SET_STATE: 'ui', ROOM_MESSAGE: 'app',
  state: 'game', track: 'game', ledger: 'game', intent: 'game'
};

const topic = String(msg.topic || '');
const payload = msg.payload;
const innerEvent = (payload && typeof payload === 'object' && payload.event)
  ? String(payload.event)
  : topic;

const WATCH = new Set(['state', 'track', 'ledger', 'SET_STATE', 'ROOM_MESSAGE']);
const kind = (payload && payload.kind) || (payload && payload.data && payload.data.kind) || null;
const isKind = kind && ['state', 'track', 'ledger', 'intent'].includes(String(kind));
const isWatch = WATCH.has(topic) || WATCH.has(innerEvent) || isKind;

if (!isWatch && topic !== 'auth_error') {
  return null;
}

const channel = EVENT_CHANNEL[innerEvent] || EVENT_CHANNEL[topic] || (isKind ? 'game' : 'app');
const counts = context.get('taxonomy') || { sys: 0, app: 0, ui: 0, agent: 0, game: 0 };
counts[channel] = (counts[channel] || 0) + 1;
context.set('taxonomy', counts);

const line = {
  at: new Date().toISOString(),
  topic,
  innerEvent,
  kind,
  channel,
  room: (payload && (payload.room || payload.data && payload.data.room)) || null,
  from: msg.alephscript && msg.alephscript.clientName
};

const recent = context.get('recent') || [];
recent.unshift(line);
if (recent.length > 40) recent.length = 40;
context.set('recent', recent);

msg.payload = { line, recent, taxonomy: counts };
msg.topic = 'oreja:' + channel;
return msg;

msg.parts = { id: 'ciudad-agg', type: 'object', key: 'snapshot' };
msg.topic = 'snapshot';
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { ok: false, statusCode: msg.statusCode, error: msg.payload };
}
return msg;

msg.parts = { id: 'ciudad-agg', type: 'object', key: 'servers' };
msg.topic = 'servers';
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { ok: false, statusCode: msg.statusCode, error: msg.payload };
}
return msg;

msg.parts = { id: 'ciudad-agg', type: 'object', key: 'firehose' };
msg.topic = 'firehose';
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { ok: false, statusCode: msg.statusCode, error: msg.payload };
}
return msg;

msg.parts = { id: 'ciudad-agg', type: 'object', key: 'cacheStats' };
msg.topic = 'cacheStats';
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { ok: false, statusCode: msg.statusCode, error: msg.payload };
}
return msg;

msg.parts = { id: 'ciudad-agg', type: 'object', key: 'cacheLineas' };
msg.topic = 'cacheLineas';
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { ok: false, statusCode: msg.statusCode, error: msg.payload };
}
return msg;

const raw = msg.payload || {};
const snapshot = raw.snapshot || { ok: false };
const serversBody = raw.servers || {};
const firehose = raw.firehose || {};
const cacheStats = raw.cacheStats || {};
const cacheLineas = raw.cacheLineas || {};

let servers = [];
if (Array.isArray(serversBody)) servers = serversBody;
else if (Array.isArray(serversBody.servers)) servers = serversBody.servers;
else if (serversBody && typeof serversBody === 'object' && serversBody.ok === false) servers = [];
else if (serversBody && typeof serversBody === 'object') {
  servers = Object.keys(serversBody).filter(k => k !== 'ok' && k !== 'statusCode' && k !== 'error')
    .map(id => ({ id, ...(typeof serversBody[id] === 'object' ? serversBody[id] : {}) }));
}

const firehoseDown = !!(firehose && firehose.ok === false);
const cacheDown = !!(cacheStats && cacheStats.ok === false);
const bothDown = firehoseDown && cacheDown;
let volume = {
  source: bothDown ? 'fixture' : 'live',
  firehose,
  cacheStats,
  cacheLineas,
  note: null,
  stats: (cacheStats && cacheStats.stats) || cacheStats || firehose || { files: 0, volumes: [] }
};

if (bothDown) {
  // Mirror fixtures/empty-volume-stats.json (Z01 blanda).
  volume = {
    ok: true,
    source: 'fixture',
    note: 'Z01 pendiente o browsers caídos — demo con volumen vacío (ver flows/fixtures/empty-volume-stats.json)',
    volumes: [],
    stats: { files: 0, bytes: 0, corpora: 0 },
    lineas: [],
    firehose,
    cacheStats,
    cacheLineas
  };
}

const DISTRICTS = {
  'Zigurat': [/vscode/i, /zigurat/i, /extension/i],
  'Runtime/MCP': [/mcp/i, /aaia/i, /copilot/i, /state.?machine/i, /novelist/i, /console/i, /editor/i],
  'Editores': [/blockly/i, /wiring/i, /prolog/i, /typed/i, /workflow/i, /n8n/i, /hypergraph/i],
  'Lore/voz': [/lore/i, /document/i, /onfalo/i, /vector/i, /asesor/i],
  'Red/stream': [/stream/i, /bot.?hub/i, /blockchain/i, /network/i, /firehose/i],
  'Infra/UI': [/vibe/i, /three/i, /ui.?sdk/i, /cache/i, /scriptorium/i, /vps/i]
};

const byDistrict = {
  'Zigurat': [], 'Runtime/MCP': [], 'Editores': [], 'Lore/voz': [], 'Red/stream': [], 'Infra/UI': [], 'Otros': []
};

for (const s of servers) {
  const label = String(s.id || s.name || s.label || JSON.stringify(s)).slice(0, 120);
  let placed = false;
  for (const [dist, patterns] of Object.entries(DISTRICTS)) {
    if (patterns.some(re => re.test(label))) {
      byDistrict[dist].push(label);
      placed = true;
      break;
    }
  }
  if (!placed) byDistrict['Otros'].push(label);
}

const health = snapshot.health || snapshot.monitor || {};
const summary = {
  at: new Date().toISOString(),
  snapshotOk: !(snapshot && snapshot.ok === false),
  serversCount: servers.length,
  volumeSource: volume.source,
  volumeNote: volume.note || null,
  volumeStats: volume.stats || cacheStats || firehose || null,
  byDistrict,
  snapshotHealth: health
};

msg.payload = summary;
msg.ciudad = { snapshot, servers, volume, byDistrict, summary };
return msg;

const stubs = global.get('ciudadIntentStubs');
const topic = String(msg.topic || '');
const cmd = (msg.payload && msg.payload.cmd) || topic;

if (cmd === 'snapshot' || topic === 'state' || (msg.payload && msg.payload.kind === 'state')) {
  const state = msg.payload && msg.payload.data ? msg.payload.data : msg.payload;
  const id = env.get('CENSUS_ID') || 'aleph';
  const me = state && state.actors && state.actors[id];
  if (me && me.zone) context.set('zone', me.zone);
  msg.topic = 'ciudadano:snapshot';
  msg.payload = { reacted: true, zone: context.get('zone'), actor: me || null };
  return [null, msg];
}

if (cmd === 'announce' || topic === 'announce') {
  msg.topic = 'compose:announce';
  return [msg, null];
}
if (cmd === 'walk' || topic === 'walk') {
  msg.topic = 'compose:walk';
  return [msg, null];
}
if (cmd === 'tick' || topic === 'tick') {
  msg.topic = 'compose:walk';
  return [msg, null];
}
return null;

const stubs = global.get('ciudadIntentStubs');
if (!stubs) {
  node.error('ciudadIntentStubs missing in globalContext');
  return null;
}
const id = env.get('CENSUS_ID') || stubs.SAMPLE_CITIZEN.censusId;
const home = env.get('HOME_ZONE') || stubs.SAMPLE_CITIZEN.homeZone;
const room = env.get('GAME_ROOM') || global.get('ZEUS_GAME_ROOM') || 'POZO_DEMO';
const game = global.get('ZEUS_GAME_ID') || 'ciudad';
let zone = context.get('zone') || home;
const topic = String(msg.topic || '');

let intent;
if (topic === 'compose:announce') {
  intent = stubs.makeAnnounceIntent(id, {
    zone: home,
    text: id + ' presente · ' + (stubs.SAMPLE_CITIZEN.agentPath || '')
  }, { game });
} else {
  const hop = stubs.nextRandomWalk(zone);
  zone = hop.nextZone;
  context.set('zone', zone);
  intent = stubs.makeWalkIntent(id, hop, { game });
}

const v = stubs.validateCiudadIntent(intent);
if (!v.ok) {
  node.status({ fill: 'red', shape: 'ring', text: v.error });
  msg.payload = { ok: false, error: v.error, intent };
  return msg;
}
node.status({ fill: 'green', shape: 'dot', text: intent.intent + ' → ' + zone });
msg.payload = stubs.toRoomIntentCommand(intent, room);
msg.topic = 'intent';
msg.ciudadano = { id, zone, intent, valid: true };
return msg;

const id = env.get('CENSUS_ID') || 'aleph';
msg.payload = {
  censusId: id,
  zone: context.get('zone') || env.get('HOME_ZONE') || 'plaza',
  last: msg.ciudadano || msg.payload,
  at: new Date().toISOString()
};
msg.topic = 'ciudadano:status';
return msg;

const stubs = global.get('ciudadIntentStubs');
const bridgeLib = global.get('operatorBridge');
if (!stubs) {
  node.error('ciudadIntentStubs missing — check settings.js functionGlobalContext');
  return null;
}
const room = global.get('ZEUS_GAME_ROOM') || 'POZO_DEMO';
const game = global.get('ZEUS_GAME_ID') || 'ciudad';
const topic = String(msg.topic || '');
const p = msg.payload || {};
const actorId = p.actorId || 'nr-mano';

let intent;
if (topic === 'wake' || p.intent === 'wake') {
  intent = stubs.makeWakeIntent(actorId, { barrioId: p.barrioId || 'vscode-extension' }, { game });
} else if (topic === 'walk' || p.intent === 'walk' || p.linkId) {
  intent = stubs.makeWalkIntent(actorId, {
    linkId: p.linkId || 'calle-plaza-zigurat',
    direction: p.direction || 'a-to-b'
  }, { game });
} else if (bridgeLib && (topic === 'operator' || p.role === 'operator')) {
  intent = stubs.makeOperatorIntent(actorId, p.intent || 'inspect', p.args || p, { game });
} else {
  intent = stubs.makeWalkIntent(actorId, {
    linkId: 'calle-plaza-zigurat',
    direction: 'a-to-b'
  }, { game });
}

const v = stubs.validateCiudadIntent(intent);
msg.mano = { intent, valid: v, at: new Date().toISOString() };
if (!v.ok) {
  node.status({ fill: 'red', shape: 'ring', text: v.error });
  msg.payload = { ok: false, error: v.error, intent };
  msg.topic = 'mano:invalid';
  return [null, msg];
}
node.status({ fill: 'green', shape: 'dot', text: intent.intent + ' ok' });
msg.payload = stubs.toRoomIntentCommand(intent, room);
msg.topic = 'intent';
return [msg, msg];

const bridgeLib = global.get('operatorBridge');
if (!bridgeLib) {
  node.error('operatorBridge missing');
  return null;
}
let bridge = context.get('bridge');
if (!bridge) {
  bridge = bridgeLib.createOperatorBridge();
  context.set('bridge', bridge);
}
const topic = String(msg.topic || '');
let msgs = [];
let slice = null;
if (topic === 'bridge:ledger' || (msg.payload && msg.payload.kind && !msg.payload.actors)) {
  msgs = bridge.onLedger(msg.payload);
} else {
  msgs = bridge.onState(msg.payload || {});
  slice = bridgeLib.projectOperatorSlice(msg.payload || {});
}
msg.payload = { alephMessages: msgs, slice, at: new Date().toISOString() };
msg.topic = 'mano:bridge';
node.status({ fill: 'blue', shape: 'dot', text: msgs.length + ' msgs' });
return msg;

const load = global.get('loadLoteAmbito');
const stubs = global.get('ciudadIntentStubs');
const ambito = global.get('Z08_AMBITO') || 'plaza-ops';
const max = global.get('POBLACION_MAX') || 24;
if (!load || !stubs) {
  node.error('loadLoteAmbito / ciudadIntentStubs missing');
  return null;
}
const lote = load();
const topic = String(msg.topic || 'lote:load');
const room = global.get('ZEUS_GAME_ROOM') || 'POZO_DEMO';
const summary = {
  ambito: lote.ambito || ambito,
  poblacionMax: lote.poblacionMax || max,
  count: lote.count,
  agents: (lote.agents || []).map((a) => ({
    censusId: a.censusId,
    homeZone: a.homeZone,
    section: a.section
  })),
  at: new Date().toISOString(),
  topic
};
node.status({
  fill: 'green',
  shape: 'dot',
  text: (lote.ambito || ambito) + ' · ' + lote.count + '/' + max
});
context.set('lote', lote);

const summaryMsg = { payload: summary, topic: 'poblacion:summary' };
if (topic === 'lote:load') {
  return [summaryMsg, null];
}

const fanouts = [];
for (const a of lote.agents || []) {
  let intent;
  if (topic === 'lote:walk') {
    const zone = context.get('zone:' + a.censusId) || a.homeZone || 'plaza';
    const hop = stubs.nextRandomWalk(zone);
    context.set('zone:' + a.censusId, hop.nextZone);
    intent = stubs.makeWalkIntent(a.censusId, hop);
  } else {
    intent = stubs.makeAnnounceIntent(a.censusId, {
      zone: a.homeZone || 'plaza',
      text: (a.displayName || a.censusId) + ' · ' + (lote.ambito || ambito)
    });
  }
  fanouts.push({
    topic: 'intent',
    payload: stubs.toRoomIntentCommand(intent, room),
    ciudadano: a
  });
}
summaryMsg.payload = Object.assign({}, summary, { emitted: fanouts.length });
summaryMsg.topic = 'poblacion:fanout';
node.send([summaryMsg, null]);
for (const m of fanouts) node.send([null, m]);
return null;
